const data = $('Procesamiento de XML').first().json.data.output

const release = $('Webhook').first().json.headers['x-release-number'] || "N/A";
const reportUrl = $('Webhook').first().json.headers['x-report-url']|| null;
const env = $('Webhook').first().json.headers['x-env'] || "N/A";
const repoName = $('Webhook').first().json.headers['x-repo-name'] || "null";

const blocks = [];

// HEADER
blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `📊 Reporte de Ejecución – ${release}`,
    emoji: true
  }
});

// INFO DEL AMBIENTE + URL
let infoText = `*Repositorio:* ${repoName}\n*Ambiente:* ${env}`;
if (reportUrl) {
  infoText += `\n*Reporte:* <${reportUrl}|Ver reporte HTML completo>`;
}

blocks.push({
  type: "section",
  text: { type: "mrkdwn", text: infoText }
});
blocks.push({ type: "divider" });

// SUMMARY
blocks.push({
  type: "section",
  text: {
    type: "mrkdwn",
    text: `*Total:* ${data.summary.total}
*Exitosas:* ${data.summary.passed}
*Fallidas:* ${data.summary.failed}
*Omitidas:* ${data.summary.skipped}
*Tiempo:* ${data.summary.executionTime}`
  }
});

blocks.push({ type: "divider" });

// DEVICES
for (const d of data.devices) {
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `• *${d.name}:* ${d.tests} pruebas – ${d.failed} fallas – ${d.skipped} omitidas`
    }
  });
}

blocks.push({ type: "divider" });

// MENSAJE FINAL SEGÚN RESULTADO
if (data.summary.failed === 0) {
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: "No se detectaron fallas.\nTodos los tests pasaron correctamente."
    }
  });
} else {
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: "Se detectaron fallas.\nEl detalle completo se encuentra en el PDF adjunto."
    }
  });
}

return [{ json: { blocks } }];

const failures =
  $('Procesamiento de XML').first().json.data.output.failuresGrouped || [];

let failuresHtml = "";

for (const group of failures) {
  const testsHtml = group.tests
    .map(t => `
      <div class="test">
        <div class="test-name">${t.testName}</div>
        <div class="test-desc">${t.description}</div>
      </div>
    `)
    .join("");

  failuresHtml += `
    <div class="failure-group">
      <div class="meta">
        <span class="label">URL:</span>
        <span class="value">
          <a href="${group.url}">${group.url}</a>
        </span>
      </div>

      <div class="meta">
        <span class="label">Módulo:</span>
        <span class="value">${group.module}</span>
      </div>

      <div class="tests">
        ${testsHtml}
      </div>
    </div>
  `;
}

// ⬅️ ESTE RETURN ES EL CAMBIO CLAVE
return [
  {
    json: {
      failuresHtml
    }
  }
];

